// apps/web/src/components/common/ProgressBar/ProgressBar.tsx
import React from 'react';

interface ProgressBarProps {
  progress: number; // 0-100
  variant?: 'primary' | 'success' | 'warning' | 'danger';
  size?: 'sm' | 'md' | 'lg';
  showLabel?: boolean;
  animated?: boolean;
  label?: string;
}

const ProgressBar: React.FC<ProgressBarProps> = ({
  progress,
  variant = 'primary',
  size = 'md',
  showLabel = true,
  animated = true,
  label,
}) => {
  // progress 0-100 범위로 제한
  const normalizedProgress = Math.min(100, Math.max(0, progress));

  const variantStyles = {
    primary: 'bg-sky-500',
    success: 'bg-emerald-500',
    warning: 'bg-amber-500',
    danger: 'bg-red-500',
  };

  const sizeStyles = {
    sm: 'h-1',
    md: 'h-2',
    lg: 'h-3',
  };

  const bgSizeStyles = {
    sm: 'h-1 bg-slate-700',
    md: 'h-2 bg-slate-700',
    lg: 'h-3 bg-slate-700',
  };

  return (
    <div className="w-full">
      {(showLabel || label) && (
        <div className="flex justify-between items-center mb-2">
          <span className="text-sm font-medium text-slate-300">{label || '진행률'}</span>
          <span className="text-sm font-semibold text-sky-400">{normalizedProgress}%</span>
