      )}
      <div className={`w-full rounded-full overflow-hidden ${bgSizeStyles[size]}`}>
        <div
          className={`${variantStyles[variant]} ${sizeStyles[size]} rounded-full transition-all duration-500 ${
            animated ? 'ease-out' : ''
