```typescript
// packages/stores/src/useLearningStore.ts
import { create } from 'zustand';
import { devtools, persist } from 'zustand/middleware';

export interface Lesson {
  id: string;
  title: string;
  description: string;
  completed: boolean;
  progress: number;
  duration: number; // minutes
  completedAt?: Date;
}

export interface LearningState {
  lessons: Lesson[];
  currentLessonId: string | null;
  totalProgress: number;
  completedCount: number;

  // Actions
  setLessons: (lessons: Lesson[]) => void;
  updateLesson: (id: string, updates: Partial<Lesson>) => void;
  setCurrentLesson: (id: string | null) => void;
  completeLesson: (id: string) => void;
  calculateProgress: () => void;
}

export const useLearningStore = create<LearningState>()(
  devtools(
    persist(
      (set) => ({
        lessons: [],
        currentLessonId: null,
        totalProgress: 0,
        completedCount: 0,

        setLessons: (lessons) =>
          set({ lessons }, false, 'setLessons'),

        updateLesson: (id, updates) =>
          set(
            (state) => ({
              lessons: state.lessons.map((lesson) =>
                lesson.id === id ? { ...lesson, ...updates } : lesson
              ),
            }),
            false,
            'updateLesson'
          ),

        setCurrentLesson: (id) =>
          set({ currentLessonId: id }, false, 'setCurrentLesson'),

        completeLesson: (id) =>
          set(
            (state) => ({
              lessons: state.lessons.map((lesson) =>
                lesson.id === id
                  ? {
                      ...lesson,
                      completed: true,
                      progress: 100,
                      completedAt: new Date(),
                    }
                  : lesson
              ),
            }),
            false,
            'completeLesson'
          ),

        calculateProgress: () =>
          set((state) => {
            const completedCount = state.lessons.filter(
              (l) => l.completed
            ).length;
            const totalProgress =
              state.lessons.length > 0
                ? Math.round(
                    (completedCount / state.lessons.length) * 100
                  )
                : 0;

            return {
              completedCount,
              totalProgress,
            };
          }, false, 'calculateProgress'),
      }),
      {
        name: 'learning-storage',
      }
    ),
    { name: 'LearningStore' }
  )
);
```

